<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Maze Exploration Bots</title>
    <style>
        body {
            background: #222;
            color: #eee;
            font-family: sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            margin: 0;
            height: 100vh;
            overflow: hidden;
        }
        #ui {
            margin-bottom: 10px;
            display: flex;
            gap: 20px;
            align-items: center;
            font-size: 18px;
            font-weight: bold;
        }
        #maze-container {
            position: relative;
            background: #333;
            border: 4px solid #555;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
        }
        canvas {
            display: block;
        }
        button {
            padding: 8px 16px;
            cursor: pointer;
            background: #44a;
            color: white;
            border: none;
            border-radius: 4px;
            font-weight: bold;
        }
        button:hover { background: #55b; }
    </style>
</head>
<body>

<div id="ui">
    <div>Completed: <span id="completed">0</span>/24</div>
    <div>Ticks: <span id="timer">0</span></div>
    <button id="reset">Reset Maze</button>
</div>
<div id="maze-container">
    <canvas id="maze" width="500" height="500"></canvas>
</div>

<script>
/** 
 * Deterministic Random Number Generator (LCG)
 */
class LCG {
    constructor(seed) { this.state = seed || Math.floor(Math.random() * 1000000); }
    next() {
        this.state = (this.state * 1664525 + 1013904223) % 4294967296;
        return this.state / 4294967296;
    }
    shuffle(array) {
        for (let i = array.length - 1; i > 0; i--) {
            const j = Math.floor(this.next() * (i + 1));
            [array[i], array[j]] = [array[j], array[i]];
        }
    }
}

const ROWS = 20, COLS = 20;
const BOT_COUNT = 24;

const windowGame = {
    elapsed: 0,
    size: { rows: ROWS, cols: COLS },
    spawn: { r: 0, c: 0 },
    exit: { r: ROWS - 1, c: COLS - 1 },
    walls: [], // [r][c] = {n, e, s, w}
    bots: [],

    reset(seed) {
        const rng = new LCG(seed);
        this.elapsed = 0;
        this.walls = this._generateMaze(rng);
        this.bots = [];

        for (let i = 0; i < BOT_COUNT; i++) {
            // Each bot gets a unique preference order for directions
            const prefs = ['n', 'e', 's', 'w'];
            rng.shuffle(prefs);

            this.bots.push({
                id: i,
                pos: { r: this.spawn.r, c: this.spawn.c },
                prevPos: { r: this.spawn.r, c: this.spawn.c },
                path: [{ r: this.spawn.r, c: this.spawn.c }],
                visited: new Set([`0,0`]),
                deadEnds: [],
                finishTick: null,
                prefs: prefs,
                color: `hsl(${(i * 360 / BOT_COUNT)}, 80%, 60%)`
            });
        }
    },

    _generateMaze(rng) {
        const walls = Array.from({ length: ROWS }, () => 
            Array.from({ length: COLS }, () => ({ n: true, e: true, s: true, w: true }))
        );
        const visited = Array.from({ length: ROWS }, () => Array(COLS).fill(false));
        const stack = [{ r: 0, c: 0 }];
        visited[0][0] = true;

        while (stack.length > 0) {
            const curr = stack[stack.length - 1];
            const neighbors = [];
            if (curr.r > 0 && !visited[curr.r - 1][curr.c]) neighbors.push({ r: curr.r - 1, c: curr.c, dir: 'n', opp: 's' });
            if (curr.c < COLS - 1 && !visited[curr.r][curr.c + 1]) neighbors.push({ r: curr.r, c: curr.c + 1, dir: 'e', opp: 'w' });
            if (curr.r < ROWS - 1 && !visited[curr.r + 1][curr.c]) neighbors.push({ r: curr.r + 1, c: curr.c + 1, dir: 's', opp: 'n' }); // Fixed index below
        }
        // Redoing generation logic for clarity and correctness
        return this._generateMazeCorrect(rng);
    },

    _generateMazeCorrect(rng) {
        const walls = Array.from({ length: ROWS }, () => 
            Array.from({ length: COLS }, () => ({ n: true, e: true, s: true, w: true }))
        );
        const visited = Array.from({ length: ROWS }, () => Array(COLS).fill(false));
        const stack = [{ r: 0, c: 0 }];
        visited[0][0] = true;

        while (stack.length > 0) {
            const curr = stack[stack.length - 1];
            const neighbors = [];
            if (curr.r > 0 && !visited[curr.r - 1][curr.c]) neighbors.push({ r: curr.r - 1, c: curr.c, dir: 'n', opp: 's' });
            if (curr.c < COLS - 1 && !visited[curr.r][curr.c + 1]) neighbors.push({ r: curr.r, c: curr.c + 1, dir: 'e', opp: 'w' });
            if (curr.r < ROWS - 1 && !visited[curr.r + 1][curr.c]) neighbors.push({ r: curr.r + 1, c: curr.c, dir: 's', opp: 'n' });
            if (curr.c > 0 && !visited[curr.r][curr.c - 1]) neighbors.push({ r: curr.r, c: curr.c - 1, dir: 'w', opp: 'e' });

            if (neighbors.length > 0) {
                const next = neighbors[Math.floor(rng.next() * neighbors.length)];
                walls[curr.r][curr.c][next.dir] = false;
                walls[next.r][next.c][next.opp] = false;
                visited[next.r][next.c] = true;
                stack.push(next);
            } else {
                stack.pop();
            }
        }
        return walls;
    },

    wallsAt(r, c) { return this.walls[r][c]; },

    tick(n) {
        for (let i = 0; i < n; i++) {
            let anyMoving = false;
            this.bots.forEach(bot => {
                if (bot.finishTick === null) {
                    anyMoving = true;
                    this._updateBot(bot);
                }
            });
            if (anyMoving) this.elapsed++;
        }
    },

    _updateBot(bot) {
        const curr = bot.pos;
        // Check if reached exit
        if (curr.r === this.exit.r && curr.c === this.exit.c) {
            bot.finishTick = this.elapsed;
            return;
        }

        // Find unvisited neighbors that are not blocked by walls
        const available = [];
        const w = this.wallsAt(curr.r, curr.c);
        if (!w.n && curr.r > 0 && !bot.visited.has(`${curr.r - 1},${curr.c}`)) available.push({ r: curr.r - 1, c: curr.c, dir: 'n' });
        if (!w.e && curr.c < COLS - 1 && !bot.visited.has(`${curr.r},${curr.c + 1}`)) available.push({ r: curr.r, c: curr.c + 1, dir: 'e' });
        if (!w.s && curr.r < ROWS - 1 && !bot.visited.has(`${curr.r + 1},${curr.c}`)) available.push({ r: curr.r + 1, c: curr.c, dir: 's' });
        if (!w.w && curr.c > 0 && !bot.visited.has(`${curr.r},${curr.c - 1}`)) available.push({ r: curr.r, c: curr.c - 1, dir: 'w' });

        if (available.length > 0) {
            // Move forward based on preference order
            let chosen = null;
            for (const pref of bot.prefs) {
                const match = available.find(a => a.dir === pref);
                if (match) { chosen = match; break; }
            }
            bot.prevPos = { ...curr };
            bot.pos = { r: chosen.r, c: chosen.c };
            bot.path.push({ ...bot.pos });
            bot.visited.add(`${bot.pos.r},${bot.pos.c}`);
        } else {
            // Mark current as dead end and backtrack
            bot.deadEnds.push({ ...curr });
            if (bot.path.length > 1) {
                bot.path.pop(); // Remove current cell from stack to find previous
                const prev = bot.path[bot.path.length - 1];
                bot.prevPos = { ...curr };
                bot.pos = { ...prev };
                bot.path.push({ ...prev }); // Every cell entered is recorded in path
            }
        }
    }
};

// Global API mapping
window.game = {
    tick: (n) => windowGame.tick(n),
    reset: (seed) => windowGame.reset(seed),
    get elapsed() { return windowGame.elapsed; },
    get size() { return windowGame.size; },
    get spawn() { return windowGame.spawn; },
    get exit() { return windowGame.exit; },
    walls: (r, c) => windowGame.wallsAt(r, c),
    get bots() { return windowGame.bots; }
};

/** 
 * Rendering Logic
 */
const canvas = document.getElementById('maze');
const ctx = canvas.getContext('2d');
const completedEl = document.getElementById('completed');
const timerEl = document.getElementById('timer');
const resetBtn = document.getElementById('reset');

let lastTickTime = 0;
const TICK_INTERVAL = 150; // ms per simulation tick

function draw() {
    const now = performance.now();
    const progress = (now - lastTickTime) / TICK_INTERVAL;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const cellSize = canvas.width / COLS;

    // Draw Walls
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 2;
    for (let r = 0; r < ROWS; r++) {
        for (let c = 0; c < COLS; c++) {
            const w = windowGame.wallsAt(r, c);
            const x = c * cellSize;
            const y = r * cellSize;
            ctx.beginPath();
            if (w.n) { ctx.moveTo(x, y); ctx.lineTo(x + cellSize, y); }
            if (w.e) { ctx.moveTo(x + cellSize, y); ctx.lineTo(x + cellSize, y + cellSize); }
            if (w.s) { ctx.moveTo(x, y + cellSize); ctx.lineTo(x + cellSize, y + cellSize); }
            if (w.w) { ctx.moveTo(x, y); ctx.lineTo(x, y + cellSize); }
            ctx.stroke();
        }
    }

    // Draw Exit
    ctx.fillStyle = 'rgba(0, 255, 0, 0.3)';
    ctx.fillRect(windowGame.exit.c * cellSize + 4, windowGame.exit.r * cellSize + 4, cellSize - 8, cellSize - 8);

    // Draw Bots with interpolation
    const interp = Math.min(1, progress);
    windowGame.bots.forEach(bot => {
        const startX = bot.prevPos.c * cellSize + cellSize / 2;
        const startY = bot.prevPos.r * cellSize + cellSize / 2;
        const endX = bot.pos.c * cellSize + cellSize / 2;
        const endY = bot.pos.r * cellSize + cellSize / 2;

        const curX = startX + (endX - startX) * interp;
        const curY = startY + (endY - startY) * interp;

        ctx.fillStyle = bot.color;
        ctx.beginPath();
        ctx.arc(curX, curY, 4, 0, Math.PI * 2);
        ctx.fill();
    });

    // Update UI
    completedEl.textContent = windowGame.bots.filter(b => b.finishTick !== null).length;
    timerEl.textContent = windowGame.elapsed;

    if (now - lastTickTime >= TICK_INTERVAL) {
        windowGame.tick(1);
        lastTickTime = now;
    }

    requestAnimationFrame(draw);
}

resetBtn.addEventListener('click', () => {
    windowGame.reset();
});

// Initialize and start
windowGame.reset();
requestAnimationFrame(draw);

</script>
</body>
</html>
